     1→'use client';
     2→
     3→import { useState, useEffect } from 'react';
     4→import { RacquetVisualization } from '@/components/visualizations/RacquetVisualization';
     5→import { RacquetFilters } from '@/components/filters/RacquetFilters';
     6→import { RacquetComparison } from '@/components/comparison/RacquetComparison';
     7→import { RecommendationEngine } from '@/components/recommendations/RecommendationEngine';
     8→import { AnalyticsDashboard } from '@/components/analytics/AnalyticsDashboard';
     9→import { useRacquetFilters } from '@/lib/hooks/useRacquetFilters';
    10→import { useRacquetComparison } from '@/lib/hooks/useRacquetComparison';
    11→import { Button } from '@/components/ui/Button';
    12→import { Card } from '@/components/ui/Card';
    13→import { LoadingSpinner } from '@/components/ui/LoadingSpinner';
    14→import { Brand } from '@/lib/types';
    15→
    16→interface RacquetData {
    17→  id: string;
    18→  model: string;
    19→  brand: string;
    20→  weight_oz: number;
    21→  head_size_sq_in: number;
    22→  swingweight: number;
    23→  flex: number;
    24→  power_avg: number;
    25→  control_avg: number;
    26→  maneuverability_avg: number;
    27→  stability_avg: number;
    28→  comfort_avg: number;
    29→  touch_feel_avg: number;
    30→  overall_avg: number;
    31→}
    32→
    33→export default function Home() {
    34→  const [racquets, setRacquets] = useState<RacquetData[]>([]);
    35→  const [brands, setBrands] = useState<Brand[]>([]);
    36→  const [loading, setLoading] = useState(true);
    37→  const [showVisualization, setShowVisualization] = useState(false);
    38→  const [currentView, setCurrentView] = useState<'visualization' | 'recommendations' | 'analytics'>('visualization');
    39→
    40→  useEffect(() => {
    41→    async function loadData() {
    42→      try {
    43→        // Load racquets
    44→        const racquetsResponse = await fetch('/api/racquets');
    45→        let racquetsData: RacquetData[] = [];
    46→        
    47→        if (racquetsResponse.ok) {
    48→          racquetsData = await racquetsResponse.json();
    49→        } else {
    50→          // Fallback to local data if API fails
    51→          const localData = await import('@/data/racquets.json');
    52→          racquetsData = localData.default as RacquetData[];
    53→        }
    54→        setRacquets(racquetsData);
    55→
    56→        // Load brands
    57→        try {
    58→          const brandsResponse = await fetch('/api/brands');
    59→          if (brandsResponse.ok) {
    60→            const brandsData = await brandsResponse.json();
    61→            setBrands(brandsData);
    62→          } else {
    63→            // Fallback to local data if API fails
    64→            const localBrands = await import('@/data/brands.json');
    65→            setBrands(localBrands.default as Brand[]);
    66→          }
    67→        } catch (brandsError) {
    68→          console.error('Error loading brands:', brandsError);
    69→          // Fallback to local data
    70→          const localBrands = await import('@/data/brands.json');
    71→          setBrands(localBrands.default as Brand[]);
    72→        }
    73→      } catch (error) {
    74→        console.error('Error loading data:', error);
    75→        // Fallback to local data
    76→        try {
    77→          const localData = await import('@/data/racquets.json');
    78→          setRacquets(localData.default as RacquetData[]);
    79→          const localBrands = await import('@/data/brands.json');
    80→          setBrands(localBrands.default as Brand[]);
    81→        } catch (localError) {
    82→          console.error('Error loading local data:', localError);
    83→        }
    84→      } finally {
    85→        setLoading(false);
    86→      }
    87→    }
    88→
    89→    loadData();
    90→  }, []);
    91→
    92→  // Use the racquet filters hook
    93→  const {
    94→    filters,
    95→    filteredRacquets,
    96→    setFilters,
    97→    resetFilters,
    98→    filterCounts,
    99→    ranges,
   100→  } = useRacquetFilters({
   101→    racquets,
   102→    brands,
   103→    persistToURL: showVisualization,
   104→  });
   105→
   106→  // Use the racquet comparison hook
   107→  const comparison = useRacquetComparison();
   108→
   109→  if (showVisualization) {
   110→    return (
   111→      <div className="min-h-screen bg-gradient-to-br from-background to-background-secondary">
   112→        {/* Navigation Header */}
   113→        <header className="border-b border-border-muted sticky top-0 bg-background/95 backdrop-blur-sm z-50">
   114→          <div className="container mx-auto px-4 py-4">
   115→            <div className="flex items-center justify-between">
   116→              <div className="flex items-center space-x-3">
   117→                <div className="w-8 h-8 rounded-full bg-primary flex items-center justify-center">
   118→                  <span className="text-white font-bold text-lg">🎾</span>
   119→                </div>
   120→                <div>
   121→                  <h1 className="text-lg font-bold text-foreground">
   122→                    Tennis Racquet Explorer
   123→                  </h1>
   124→                  <p className="text-xs text-foreground-muted">
   125→                    Interactive Data Exploration
   126→                  </p>
   127→                </div>
   128→              </div>
   129→              <div className="flex items-center gap-2">
   130→                <div className="flex bg-gray-100 rounded-lg p-1 mr-4">
   131→                  <button
   132→                    onClick={() => setCurrentView('visualization')}
   133→                    className={`px-3 py-1 text-sm font-medium rounded-md transition-colors ${
   134→                      currentView === 'visualization' 
   135→                        ? 'bg-white text-gray-900 shadow-sm' 
   136→                        : 'text-gray-600 hover:text-gray-900'
   137→                    }`}
   138→                  >
   139→                    Explore
   140→                  </button>
   141→                  <button
   142→                    onClick={() => setCurrentView('recommendations')}
   143→                    className={`px-3 py-1 text-sm font-medium rounded-md transition-colors ${
   144→                      currentView === 'recommendations' 
   145→                        ? 'bg-white text-gray-900 shadow-sm' 
   146→                        : 'text-gray-600 hover:text-gray-900'
   147→                    }`}
   148→                  >
   149→                    Recommendations
   150→                  </button>
   151→                  <button
   152→                    onClick={() => setCurrentView('analytics')}
   153→                    className={`px-3 py-1 text-sm font-medium rounded-md transition-colors ${
   154→                      currentView === 'analytics' 
   155→                        ? 'bg-white text-gray-900 shadow-sm' 
   156→                        : 'text-gray-600 hover:text-gray-900'
   157→                    }`}
   158→                  >
   159→                    Analytics
   160→                  </button>
   161→                </div>
   162→                <Button 
   163→                  variant={comparison.isComparing ? "default" : "outline"}
   164→                  onClick={comparison.toggleComparison}
   165→                  className="text-sm"
   166→                >
   167→                  {comparison.isComparing ? 'Hide Comparison' : 'Compare Racquets'} 
   168→                  {comparison.selectedRacquets.length > 0 && (
   169→                    <span className="ml-2 bg-primary text-white text-xs px-2 py-1 rounded-full">
   170→                      {comparison.selectedRacquets.length}
   171→                    </span>
   172→                  )}
   173→                </Button>
   174→                <Button 
   175→                  variant="outline" 
   176→                  onClick={() => setShowVisualization(false)}
   177→                  className="text-sm"
   178→                >
   179→                  ← Back to Home
   180→                </Button>
   181→              </div>
   182→            </div>
   183→          </div>
   184→        </header>
   185→
   186→        <main className="container mx-auto px-4 py-8">
   187→          {loading ? (
   188→            <Card className="p-12 text-center">
   189→              <LoadingSpinner size="lg" />
   190→              <p className="mt-4 text-foreground-muted">Loading racquet data...</p>
   191→            </Card>
   192→          ) : (
   193→            <div className="space-y-6">
   194→              {/* Comparison Section */}
   195→              <RacquetComparison />
