/* Enhanced Mobile Responsiveness */
@media (max-width: 768px) {
  /* Typography scaling */
  .tennis-hero-title {
    font-size: 2.5rem;
    line-height: 1.1;
  }

  /* Container adjustments */
  .container {
    padding-left: 1rem;
    padding-right: 1rem;
  }

  /* Touch-friendly button sizes */
  .btn-mobile {
    min-height: 44px;
    min-width: 44px;
    padding: 0.75rem 1.5rem;
  }

  /* Card spacing adjustments */
  .card-mobile {
    margin: 0.5rem;
    padding: 1rem;
  }

  /* Tab navigation mobile */
  .tab-nav-mobile {
    flex-direction: column;
    gap: 0.5rem;
  }

  .tab-nav-mobile button {
    width: 100%;
    padding: 0.75rem;
    justify-content: center;
  }

  /* Grid adjustments */
  .grid-mobile-1 {
    grid-template-columns: 1fr;
    gap: 1rem;
  }

  /* Visualization mobile adjustments */
  .viz-mobile {
    height: 300px;
    min-height: 300px;
  }

  /* Filter sidebar mobile */
  .filters-mobile {
    position: fixed;
    top: 0;
    left: 0;
    width: 100%;
    height: 100%;
    background: var(--background);
    z-index: 1000;
    transform: translateX(-100%);
    transition: transform 0.3s ease-in-out;
    overflow-y: auto;
    padding: 1rem;
  }

  .filters-mobile.open {
    transform: translateX(0);
  }

  /* Header mobile adjustments */
  .header-mobile {
    padding: 0.75rem 1rem;
  }

  .header-mobile .nav-buttons {
    flex-direction: column;
    gap: 0.5rem;
    width: 100%;
  }

  /* Stats grid mobile */
  .stats-grid-mobile {
    grid-template-columns: repeat(2, 1fr);
    gap: 1rem;
  }
}

@media (max-width: 480px) {
  /* Extra small screens */
  .tennis-hero-title {
    font-size: 2rem;
  }

  /* Single column layout */
  .features-grid-mobile {
    grid-template-columns: 1fr;
  }

  /* Smaller text */
  .text-mobile-small {
    font-size: 0.875rem;
  }

  /* Compact cards */
  .card-mobile-compact {
    padding: 0.75rem;
    margin: 0.25rem;
  }
}

