toolUseResult.originalFile:
@import "tailwindcss";
@import url('https://fonts.googleapis.com/css2?family=Inter:wght@400;500;600;700&display=swap');

:root {
  /* Tennis Court Colors */
  --court-green: #228B22;
  --court-green-light: #32CD32;
  --court-green-dark: #006400;
  --tennis-ball: #CCFF00;
  --tennis-ball-dark: #9ACD32;

  /* Neutral Colors */
  --background: #ffffff;
  --background-secondary: #f8faf9;
  --foreground: #1a1a1a;
  --foreground-muted: #6b7280;
  --border: #e5e7eb;
  --border-muted: #f3f4f6;

  /* Semantic Colors */
  --success: var(--court-green);
  --warning: #f59e0b;
  --error: #ef4444;
  --info: #3b82f6;
}

@theme inline {
  /* Colors */
  --color-background: var(--background);
  --color-background-secondary: var(--background-secondary);
  --color-foreground: var(--foreground);
  --color-foreground-muted: var(--foreground-muted);
  --color-border: var(--border);
  --color-border-muted: var(--border-muted);

  /* Brand Colors */
  --color-primary: var(--court-green);
  --color-primary-light: var(--court-green-light);
  --color-primary-dark: var(--court-green-dark);
  --color-accent: var(--tennis-ball);
  --color-accent-dark: var(--tennis-ball-dark);

  /* Semantic Colors */
  --color-success: var(--success);
  --color-warning: var(--warning);
  --color-error: var(--error);
  --color-info: var(--info);

  /* Typography */
  --font-family-sans: 'Inter', system-ui, -apple-system, sans-serif;
  --font-family-mono: 'Fira Code', 'Monaco', 'Consolas', monospace;

  /* Spacing & Sizing */
  --radius: 0.5rem;
  --radius-lg: 0.75rem;
  --radius-xl: 1rem;

  /* Shadows */
  --shadow-sm: 0 1px 2px 0 rgb(0 0 0 / 0.05);
  --shadow: 0 1px 3px 0 rgb(0 0 0 / 0.1), 0 1px 2px -1px rgb(0 0 0 / 0.1);
  --shadow-md: 0 4px 6px -1px rgb(0 0 0 / 0.1), 0 2px 4px -2px rgb(0 0 0 / 0.1);
  --shadow-lg: 0 10px 15px -3px rgb(0 0 0 / 0.1), 0 4px 6px -4px rgb(0 0 0 / 0.1);
}

@media (prefers-color-scheme: dark) {
  :root {
    --background: #0a0a0a;
    --background-secondary: #111111;
    --foreground: #ededed;
    --foreground-muted: #9ca3af;
    --border: #374151;
    --border-muted: #1f2937;
  }
}

body {
  background: var(--background);
  color: var(--foreground);
  font-family: var(--font-family-sans);
  font-feature-settings: 'rlig' 1, 'calt' 1;
  -webkit-font-smoothing: antialiased;
  -moz-osx-font-smoothing: grayscale;
}

/* Custom scrollbar */
::-webkit-scrollbar {
  width: 6px;
  height: 6px;
}

::-webkit-scrollbar-track {
  background: var(--background-secondary);
}

::-webkit-scrollbar-thumb {
  background: var(--border);
  border-radius: 3px;
}

::-webkit-scrollbar-thumb:hover {
  background: var(--foreground-muted);
}

/* Selection */
::selection {
  background-color: var(--tennis-ball);
  color: var(--foreground);
}

/* Focus styles */
*:focus-visible {
  outline: 2px solid var(--court-green);
  outline-offset: 2px;
}

/* Tennis-themed animations */
@keyframes tennis-bounce {
  0%, 100% {
    transform: translateY(0);
  }
  50% {
    transform: translateY(-10px);
  }
}

@keyframes tennis-spin {
  from {
    transform: rotate(0deg);
  }
  to {
    transform: rotate(360deg);
  }
}

@keyframes court-line-draw {
  from {
    stroke-dashoffset: 100%;
  }
  to {
    stroke-dashoffset: 0%;
  }
}

.tennis-bounce {
  animation: tennis-bounce 2s ease-in-out infinite;
}

.tennis-spin {
  animation: tennis-spin 10s linear infinite;
}

.court-line {
  stroke-dasharray: 5, 5;
  animation: court-line-draw 2s ease-in-out;
}

/* Enhanced gradient backgrounds */
.tennis-gradient-bg {
  background: linear-gradient(135deg, 
    var(--court-green-light) 0%, 
    var(--court-green) 50%, 
    var(--court-green-dark) 100%);
}

.tennis-ball-gradient {
  background: radial-gradient(circle at 30% 30%, 
    var(--tennis-ball) 0%, 
    var(--tennis-ball-dark) 70%);
}

/* Hover effects for tennis elements */
.tennis-card-hover {
  transition: all 0.3s cubic-bezier(0.4, 0, 0.2, 1);
}

.tennis-card-hover:hover {
  transform: translateY(-4px) scale(1.02);
  box-shadow: 0 20px 25px -5px rgba(0, 0, 0, 0.1), 
              0 10px 10px -5px rgba(0, 0, 0, 0.04);
}

/* Court texture overlay */
.court-texture {
  background-image: 
    linear-gradient(45deg, transparent 25%, rgba(34, 139, 34, 0.05) 25%), 
    linear-gradient(-45deg, transparent 25%, rgba(34, 139, 34, 0.05) 25%), 
    linear-gradient(45deg, rgba(34, 139, 34, 0.05) 75%, transparent 75%), 
    linear-gradient(-45deg, rgba(34, 139, 34, 0.05) 75%, transparent 75%);
  background-size: 20px 20px;
  background-position: 0 0, 0 10px, 10px -10px, -10px 0px;
}

/* Responsive text scaling for tennis theme */
@media (max-width: 768px) {
  .tennis-hero-title {
    font-size: 2.5rem;
    line-height: 1.1;
  }
}

/* Data visualization enhancements */
.viz-tooltip {
  backdrop-filter: blur(8px);
  background: rgba(0, 0, 0, 0.85);
  border: 1px solid var(--court-green);
}

.data-point-tennis {
  filter: drop-shadow(0 2px 4px rgba(34, 139, 34, 0.2));
}

.data-point-tennis:hover {
  filter: drop-shadow(0 4px 8px rgba(34, 139, 34, 0.4));
}

input.new_string:
.data-point-tennis:hover {
  filter: drop-shadow(0 4px 8px rgba(34, 139, 34, 0.4));
}

/* Enhanced Skeleton Loading Screens */
.skeleton {
  background: linear-gradient(90deg, 
    var(--border-muted) 25%, 
    var(--background-secondary) 50%, 
    var(--border-muted) 75%);
  background-size: 200% 100%;
  animation: skeleton-loading 1.5s infinite;
  border-radius: var(--radius);
}

@keyframes skeleton-loading {
  0% {
    background-position: 200% 0;
  }
  100% {
    background-position: -200% 0;
  }
}

.skeleton-text {
  height: 1rem;
  margin-bottom: 0.5rem;
}

.skeleton-text.large {
  height: 1.5rem;
}

.skeleton-text.small {
  height: 0.75rem;
}

.skeleton-card {
  padding: 1rem;
  height: 200px;
}

.skeleton-chart {
  height: 300px;
  width: 100%;
}

.skeleton-avatar {
  width: 40px;
  height: 40px;
  border-radius: 50%;
}

/* Accessibility Improvements */
.sr-only {
  position: absolute;
  width: 1px;
  height: 1px;
  padding: 0;
  margin: -1px;
  overflow: hidden;
  clip: rect(0, 0, 0, 0);
  white-space: nowrap;
  border: 0;
}

/* Skip navigation */
.skip-nav {
  position: absolute;
  top: -40px;
  left: 6px;
  background: var(--primary);
  color: white;
  padding: 8px;
  text-decoration: none;
  border-radius: var(--radius);
  z-index: 1000;
  transition: top 0.3s;
}

.skip-nav:focus {
  top: 6px;
}

/* High contrast mode support */
@media (prefers-contrast: high) {
  :root {
    --border: #000000;
    --border-muted: #333333;
    --foreground: #000000;
    --background: #ffffff;
  }
}

/* Reduced motion support */
@media (prefers-reduced-motion: reduce) {
  *,
