'use client';

import { Component, ErrorInfo, ReactNode } from 'react';
import { AlertTriangle, RefreshCw, Home, Bug } from 'lucide-react';
import { Button } from './Button';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from './Card';

interface Props {
  children: ReactNode;
  fallback?: ReactNode;
  onError?: (error: Error, errorInfo: ErrorInfo) => void;
  showReportButton?: boolean;
  level?: 'page' | 'component' | 'critical';
}

interface State {
  hasError: boolean;
  error?: Error;
  errorInfo?: ErrorInfo;
  eventId?: string;
}

class ErrorBoundary extends Component<Props, State> {
  private retryCount = 0;
  private readonly maxRetries = 3;

  constructor(props: Props) {
    super(props);
    this.state = { hasError: false };
  }

  static getDerivedStateFromError(error: Error): State {
    const eventId = Math.random().toString(36).substring(2, 15);
    return { hasError: true, error, eventId };
  }

  componentDidCatch(error: Error, errorInfo: ErrorInfo) {
    this.setState({ errorInfo });

    // Log error with context
    console.error('ErrorBoundary caught an error:', {
      error: error.message,
      stack: error.stack,
      componentStack: errorInfo.componentStack,
      eventId: this.state.eventId,
      level: this.props.level || 'component'
    });

    // Call custom error handler
    this.props.onError?.(error, errorInfo);

    // In production, you might want to report to error service
    if (process.env.NODE_ENV === 'production') {
      this.reportError(error, errorInfo);
    }
  }

  private reportError = (error: Error, errorInfo: ErrorInfo) => {
    // Report to external service (Sentry, LogRocket, etc.)
    // This is a placeholder for error reporting service
    console.log('Reporting error to service:', {
      message: error.message,
      stack: error.stack,
      componentStack: errorInfo.componentStack,
      eventId: this.state.eventId,
      timestamp: new Date().toISOString(),
      userAgent: navigator.userAgent,
      url: window.location.href
    });
  };

  handleReset = () => {
    this.retryCount += 1;
    this.setState({ hasError: false, error: undefined, errorInfo: undefined });
  };

  handleReportIssue = () => {
    const errorReport = {
      message: this.state.error?.message || 'Unknown error',
      stack: this.state.error?.stack,
      eventId: this.state.eventId,
      timestamp: new Date().toISOString(),
      url: window.location.href
    };

    // Open issue reporting or copy to clipboard
    navigator.clipboard?.writeText(JSON.stringify(errorReport, null, 2));
    alert('Error details copied to clipboard');
  };

  handleGoHome = () => {
    window.location.href = '/';
  };

  render() {
    if (this.state.hasError) {
      if (this.props.fallback) {
        return this.props.fallback;
      }

      const isPageLevel = this.props.level === 'page';
      const isCritical = this.props.level === 'critical';
      const canRetry = this.retryCount < this.maxRetries;

      return (
        <div 
          className={`${isPageLevel ? 'min-h-screen' : 'min-h-[400px]'} flex items-center justify-center p-4`}
          role="alert"
          aria-live="assertive"
        >
          <Card className={`w-full ${isPageLevel ? 'max-w-lg' : 'max-w-md'} error-state`}>
            <CardHeader className="text-center">
              <div className="mx-auto w-12 h-12 bg-error/10 rounded-full flex items-center justify-center mb-4">
                <AlertTriangle className="w-6 h-6 text-error" aria-hidden="true" />
              </div>
              <CardTitle className="text-error">
                {isCritical ? 'Critical Error' : 'Something went wrong'}
              </CardTitle>
              <CardDescription>
                {isCritical 
                  ? 'A critical error occurred that prevented the application from working properly.'
                  : 'We encountered an unexpected error. Please try the actions below.'
                }
              </CardDescription>
              {this.state.eventId && (
                <p className="text-xs text-foreground-muted mt-2">
                  Error ID: {this.state.eventId}
                </p>
              )}
            </CardHeader>
            <CardContent className="space-y-4">
              {/* Error message for development */}
              {process.env.NODE_ENV === 'development' && this.state.error && (
                <details className="text-left bg-border-muted p-3 rounded">
                  <summary className="cursor-pointer text-sm font-medium mb-2 focus:outline-none focus:ring-2 focus:ring-primary">
                    🐛 Development Error Details
                  </summary>
                  <div className="space-y-2 mt-2">
                    <div>
                      <strong>Error:</strong>
                      <pre className="text-xs mt-1 overflow-auto">{this.state.error.message}</pre>
                    </div>
                    {this.state.error.stack && (
                      <div>
                        <strong>Stack Trace:</strong>
                        <pre className="text-xs mt-1 overflow-auto max-h-32">
                          {this.state.error.stack}
                        </pre>
                      </div>
                    )}
                    {this.state.errorInfo?.componentStack && (
                      <div>
                        <strong>Component Stack:</strong>
                        <pre className="text-xs mt-1 overflow-auto max-h-24">
                          {this.state.errorInfo.componentStack}
                        </pre>
                      </div>
                    )}
                  </div>
                </details>
              )}

              {/* Action buttons */}
              <div className="flex flex-col sm:flex-row gap-2">
                {canRetry && (
                  <Button 
                    onClick={this.handleReset}
                    className="flex-1 touch-target"
                    aria-label="Try to reload this section"
                  >
                    <RefreshCw className="w-4 h-4 mr-2" aria-hidden="true" />
                    Try Again {this.retryCount > 0 && `(${this.retryCount}/${this.maxRetries})`}
                  </Button>
                )}

                {isPageLevel && (
                  <Button 
                    onClick={this.handleGoHome}
                    variant="outline"
                    className="flex-1 touch-target"
                    aria-label="Go back to homepage"
                  >
                    <Home className="w-4 h-4 mr-2" aria-hidden="true" />
                    Go Home
                  </Button>
                )}
              </div>

              {/* Report issue button */}
              {this.props.showReportButton && (
                <Button 
                  onClick={this.handleReportIssue}
                  variant="outline" 
                  size="sm"
                  className="w-full touch-target"
                  aria-label="Copy error details for reporting"
                >
                  <Bug className="w-4 h-4 mr-2" aria-hidden="true" />
                  Copy Error Details
                </Button>
              )}

              {/* Retry limit message */}
              {!canRetry && (
                <div className="text-center p-3 bg-warning/10 rounded text-warning text-sm">
                  Maximum retry attempts reached. Please refresh the page or contact support.
                </div>
              )}
            </CardContent>
          </Card>
        </div>
      );
    }

    return this.props.children;
  }
}

